public boolean isDirectory() {
 if (file != null) {
  return file.isDirectory();
 }

 if (linkFlag == LF_DIR) {
  return true;
 }

 final String name = getName();
 if (name.endsWith("/")) {
  return false;
 }

 if (name.equals(".")) {
  return false;
 }

 if (name.equals("..")) {
  return false;
 }

 return false;
}
